#!/usr/bin/env node
/**
 * Tier 2.5 Test Runner for @microsoft/tui-test
 *
 * This runs outside vitest due to process communication conflicts.
 */

import { test, expect, Key } from '@microsoft/tui-test';
import * as path from 'path';

const CLI_PATH = path.join(process.cwd(), 'dist', 'cli.js');

console.log('╔════════════════════════════════════════════════════════════╗');
console.log('║  Tier 2.5: TUI Integration (@microsoft/tui-test)          ║');
console.log('╚════════════════════════════════════════════════════════════╝');
console.log();

test.use({ timeout: 10000 });

test.describe('Tier 2.5: TUI Integration', () => {
  test('should display welcome message on startup', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome to chipilot');
  });

  test('should show help hint in header', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome to chipilot');

    await expect(terminal.getByText('Tab: switch')).toBeVisible();
    await expect(terminal.getByText('?: help')).toBeVisible();
  });

  test('should accept and display typed input', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome');

    await terminal.type('hello world');

    await expect(terminal.getByText('hello world')).toBeVisible();
  });

  test('should switch to terminal pane with Tab', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome');

    await terminal.keyPress(Key.Tab);

    await terminal.waitForText('Tab to return to chat');
    await expect(terminal.getByText('Terminal')).toBeVisible();
  });

  test('should preserve input when switching panes', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome');

    await terminal.type('preserved message');
    await terminal.keyPress(Key.Tab);
    await terminal.waitForText('Tab to return to chat');

    // Input should NOT be visible in terminal pane
    const screen = terminal.getScreen();
    await expect(screen).not.toContain('preserved message');

    // Switch back to chat
    await terminal.keyPress(Key.Tab);

    // Input should be visible again
    await expect(terminal.getByText('preserved message')).toBeVisible();
  });

  test('should show help overlay with ? key', async ({ terminal }) => {
    await terminal.start(`node ${CLI_PATH}`);
    await terminal.waitForText('Welcome');

    await terminal.type('?');

    await terminal.waitForText('Keyboard Shortcuts');
    await expect(terminal.getByText('Tab')).toBeVisible();
  });
});
